from pwn import *
context.log_level='error'

def recv_pkt(r,timeout=1.0):
    data=b''
    while True:
        b=r.recv(1,timeout=timeout)
        if not b:
            return None
        data+=b
        if data.endswith(b'\x03\x00'):
            return data

def send_hummus(r,s):
    r.send(b'\x2a'+s+b'\x03')

for i in range(3):
    try:
        r=remote('pwn.chal.csaw.io',4242)
        print('connected')
        recv_pkt(r)
        send_hummus(r,b'H-mm-_')
        print('resp',recv_pkt(r))
        r.close()
        break
    except Exception as e:
        print('fail',e)
